// Dream symbol dictionary for the Dream Interpreter feature.
//
// This is the V1 (heuristic) version — we match user-input dream text
// against known symbolic keywords and surface Jungian / archetypal
// interpretations. In a later sprint we'll wrap the same flow in an
// LLM call for deeper, personalised analysis.
//
// Symbol entries cover the ~100 most common universal dream motifs drawn
// from Jung's archetypal framework + Gestalt dream work + common modern
// dream research. NOT a fortune-telling lookup — framed as reflective
// prompts the dreamer can consider.

export interface DreamSymbol {
  /** Lowercase keywords that match this symbol */
  keywords: string[];
  /** Archetypal meaning — poetic, not prescriptive */
  meaning: string;
  /** A reflective question the dreamer can hold */
  reflection: string;
}

export const DREAM_SYMBOLS: DreamSymbol[] = [
  { keywords: ['water', 'ocean', 'sea', 'river', 'lake', 'pool', 'rain', 'flood'], meaning: 'Water in dreams carries the unconscious, emotion, and the flow of feeling. Clear water suggests clarity of feeling; turbulent water shows emotional intensity or chaos; deep water hints at the depths of the psyche itself.', reflection: 'What feeling am I swimming in right now — and is it carrying me or drowning me?' },
  { keywords: ['fire', 'flame', 'burning', 'inferno', 'bonfire', 'candle'], meaning: 'Fire is transformation, passion, destruction of the old. It purifies as it consumes. A controlled flame is creative energy; a wildfire is overwhelming force that wants release.', reflection: 'What in my life is burning away — and what new form wants to emerge from the ashes?' },
  { keywords: ['flying', 'fly', 'flew', 'flight', 'soaring'], meaning: 'Flying is liberation — rising above limitation, seeing with perspective, shedding what was holding you down. It can also be escape from what you don\'t want to face.', reflection: 'Am I rising into freedom — or flying to avoid landing?' },
  { keywords: ['falling', 'fall', 'fell', 'plummeting'], meaning: 'Falling often signals loss of control, fear of failure, or the need to let go of something you\'ve been gripping. The landing — what happens at the bottom — matters more than the fall itself.', reflection: 'What am I afraid of losing my grip on — and what if I just let go?' },
  { keywords: ['teeth', 'tooth', 'losing teeth', 'broken teeth'], meaning: 'Teeth falling out is one of the most common dreams. Classically: anxiety about appearance, aging, losing power or voice. Modern dream research links it to stress and transitions.', reflection: 'Where do I feel I\'m losing my bite — my ability to speak, defend, or assert?' },
  { keywords: ['chase', 'chased', 'chasing', 'running from', 'pursued'], meaning: 'Being chased means something is trying to get your attention — a shadow part, a responsibility, a truth. You can\'t outrun it. The chaser is almost always a part of you.', reflection: 'What is chasing me — and what if I turned and faced it?' },
  { keywords: ['naked', 'nude', 'unclothed', 'no clothes'], meaning: 'Nakedness in dreams is vulnerability, authenticity, or fear of exposure. In private it may be liberation; in public it is typically anxiety about being seen, judged, or found out.', reflection: 'Where am I afraid of being seen as I really am?' },
  { keywords: ['snake', 'serpent', 'cobra', 'python', 'viper'], meaning: 'Snakes are transformation (they shed their skin), wisdom, hidden knowledge, and sometimes sexual energy. They also represent the shadow — what lurks unseen. Shedding skin is renewal.', reflection: 'What part of me is ready to shed an old skin?' },
  { keywords: ['death', 'dying', 'died', 'corpse', 'funeral'], meaning: 'Death in dreams almost never means physical death. It means endings, transformations, or the death of an old self. Something is completing. Mourn it, then look at what is being born.', reflection: 'What part of me is ending — and what new self is waiting to emerge?' },
  { keywords: ['house', 'home', 'rooms'], meaning: 'A house in dreams is the self. Rooms are aspects of you. Discovering new rooms suggests undiscovered potential. Basements are the unconscious; attics are spirit or memory; the kitchen is nourishment.', reflection: 'Which room of me am I in right now — and what room haven\'t I visited in years?' },
  { keywords: ['baby', 'infant', 'newborn', 'pregnancy', 'pregnant'], meaning: 'Babies represent new life, new projects, new possibilities that are still fragile. Pregnancy is creative gestation — something is growing in you. Abandoning a baby warns you might be neglecting a new potential.', reflection: 'What tender new thing is growing in me — and am I tending it?' },
  { keywords: ['car', 'driving', 'vehicle', 'accident', 'crash'], meaning: 'Cars are your direction, your ability to navigate life. Who\'s driving? Are you in control? A crash or brake failure signals something is out of your control — or warns you\'re heading somewhere you shouldn\'t.', reflection: 'Who is driving my life right now — and am I at the wheel?' },
  { keywords: ['door', 'doorway', 'gate'], meaning: 'A door is an opportunity, a choice, a threshold between states. Opening a door is taking a step; a closed door is a missed chance or a wise boundary.', reflection: 'What door am I standing at — and why haven\'t I opened it yet?' },
  { keywords: ['forest', 'woods', 'trees'], meaning: 'Forests are the unconscious mind — dense, mysterious, full of life you can\'t see. Getting lost in a forest suggests you\'re in a phase where the map doesn\'t work yet.', reflection: 'What is this unfamiliar territory asking me to discover?' },
  { keywords: ['mountain', 'climbing', 'summit', 'peak'], meaning: 'Mountains represent goals, challenges, and spiritual ascent. Climbing is ambition or inner development. Reaching the top is accomplishment — but also the moment when you see you must descend again.', reflection: 'What am I climbing toward — and why?' },
  { keywords: ['lost', 'can\'t find', 'missing'], meaning: 'Being lost signals a transition, a loss of direction, or a need to find a new path. You haven\'t failed — you\'ve left the old route. The new one hasn\'t appeared yet.', reflection: 'What old map am I trying to follow that stopped working?' },
  { keywords: ['school', 'test', 'exam', 'classroom'], meaning: 'School dreams usually surface during periods of being evaluated or feeling unprepared. Being in school as an adult signals you\'re in a learning phase whether you want to be or not.', reflection: 'What am I being asked to learn right now?' },
  { keywords: ['bird', 'birds', 'flying animal'], meaning: 'Birds carry messages — from the psyche, the divine, the future. A dark bird is often shadow content asking to be looked at; bright birds are spirit, hope, freedom.', reflection: 'What message is trying to reach me that I keep flying past?' },
  { keywords: ['cat', 'cats', 'feline'], meaning: 'Cats are independence, intuition, feminine power, and the sacred mysterious. In many traditions they see the invisible. A cat in your dream may be your own unspoken wisdom.', reflection: 'What in me knows without speaking?' },
  { keywords: ['dog', 'dogs', 'puppy'], meaning: 'Dogs are loyalty, friendship, unconditional love, and often the loving part of yourself. A threatening dog may be trust that has been wounded.', reflection: 'What does loyalty mean to me right now — given to whom, received from whom?' },
  { keywords: ['spider', 'web'], meaning: 'Spiders are weavers, creators of webs (fate, relationships, creation). They can represent feminine creative power or feelings of being caught in something complicated.', reflection: 'What web am I weaving — or tangled in?' },
  { keywords: ['mirror', 'reflection'], meaning: 'Mirrors reveal what you cannot see directly about yourself. The reflection may show you as you are, as you fear you are, or as you could be.', reflection: 'What does this mirror want me to see?' },
  { keywords: ['child', 'children', 'young'], meaning: 'Children in dreams often represent your inner child, innocence, creativity, or parts of you that have been left behind. They ask to be remembered or tended.', reflection: 'What part of my younger self is asking for attention?' },
  { keywords: ['hair', 'haircut', 'balding'], meaning: 'Hair is vitality, identity, attractiveness. Cutting hair is a fresh start or loss of old self; losing hair may signal anxiety about power or self-image.', reflection: 'What aspect of my identity is shifting?' },
  { keywords: ['money', 'wealth', 'gold', 'rich', 'poor'], meaning: 'Money represents self-worth, value, power, and energy exchange. Finding money suggests recognizing your value; losing money, giving it away, or being broke can point to depletion or perceived lack of worth.', reflection: 'Where do I currently place my value — and is that serving me?' },
  { keywords: ['war', 'battle', 'fighting', 'army'], meaning: 'Conflict dreams reflect inner struggle — often between parts of yourself. Who is fighting whom? Usually both sides are you, warring over a real tension.', reflection: 'What two parts of me are at war — and what would peace between them look like?' },
  { keywords: ['darkness', 'dark', 'night', 'black'], meaning: 'Darkness is the unknown, the unconscious, what you cannot yet see. It is not inherently fearful — it is rich with possibility that hasn\'t been illuminated.', reflection: 'What am I being invited to sit with, before I try to understand it?' },
  { keywords: ['light', 'bright', 'shining', 'sun'], meaning: 'Light is consciousness, clarity, insight, truth. It reveals what darkness obscured. Dazzling light can also be overwhelming — truth all at once.', reflection: 'What is becoming clear to me that I can no longer avoid?' },
  { keywords: ['lover', 'kiss', 'romance', 'ex', 'partner'], meaning: 'Romantic dreams about specific people are rarely about them — they are about qualities you associate with them. Kissing someone can signal integration of those qualities into yourself.', reflection: 'What quality of this person do I need to claim in me?' },
  { keywords: ['animal', 'creature', 'beast'], meaning: 'Animals represent instinctual, primal aspects of the self. Wild animals are your untamed nature; tame ones are your relationship with your own instincts. What does the animal want?', reflection: 'What does my wild self want from me?' },
  // ─── Second batch (2026-04-25): expanded from 30 → 80 symbols for
  // wider offline fallback coverage. Each entry same format. ────────
  { keywords: ['bridge'], meaning: 'A bridge is a passage between states — from one self to another, one chapter to the next. Crossing it is committing to the change. A collapsing bridge warns against moving before the foundation holds.', reflection: 'What crossing am I in the middle of — and is it ready to bear my weight?' },
  { keywords: ['stairs', 'staircase', 'climbing stairs'], meaning: 'Ascending stairs is development, insight, rising into higher awareness. Descending is returning to the unconscious, to the body, to something older. Endless or missing stairs suggest a transition without a map.', reflection: 'Am I climbing toward clarity or descending into what I\'ve been avoiding?' },
  { keywords: ['basement', 'cellar', 'underground'], meaning: 'The basement is the unconscious — what has been stored, buried, or forgotten. Finding rooms in the basement is meeting neglected parts of yourself. Flooded basements signal overwhelm from what was kept below.', reflection: 'What have I tucked away down there that is now asking to be seen?' },
  { keywords: ['attic', 'roof', 'upper room'], meaning: 'The attic is memory, spirit, ancestral inheritance, the higher self. What you find in the attic is what your lineage or your soul has been holding for you.', reflection: 'What stored-away thing is asking to come down into daily life?' },
  { keywords: ['elevator', 'lift'], meaning: 'Elevators are rapid shifts in consciousness or status — rising or falling without the step-by-step climb. Stuck elevators signal a transition that has stalled; runaway ones signal a change you aren\'t controlling.', reflection: 'What change is moving me faster than I\'m ready for — or slower than I can bear?' },
  { keywords: ['plane', 'airplane', 'airport', 'flight delayed'], meaning: 'Planes are ambitious journeys, leaving one reality for another. Missing a flight is often the dreaming mind commenting on a missed opportunity you already sense.', reflection: 'What flight have I been delaying — and what\'s the cost of not boarding?' },
  { keywords: ['train', 'railway', 'track'], meaning: 'Trains are collective life direction — the track is set, but you can get on, off, or stay. Missing a train is a fear of being left behind by a current you\'re part of.', reflection: 'What current am I watching move without me — and do I actually want to catch it?' },
  { keywords: ['boat', 'ship', 'sailing'], meaning: 'Boats carry you across emotional seas. How well you navigate reflects your current relationship to feeling. A sinking boat warns of being overwhelmed; a sturdy boat in rough water is resilience.', reflection: 'What emotional sea am I crossing — and am I seaworthy for it?' },
  { keywords: ['storm', 'thunder', 'lightning', 'hurricane'], meaning: 'Storms are emotional upheaval — often something that has been building up and now needs release. Lightning strikes are sudden insight or shock; thunder is the delayed resonance of what you\'ve already seen.', reflection: 'What has been building that is ready to break open?' },
  { keywords: ['snow', 'ice', 'frozen'], meaning: 'Snow and ice speak of emotional stillness — sometimes beautiful rest, sometimes frozen feeling. Melting ice is feeling beginning to flow again; being trapped in ice is a part of you suspended.', reflection: 'What feeling have I frozen to survive — and is it time to let it thaw?' },
  { keywords: ['wind', 'breeze', 'gale'], meaning: 'Wind is invisible movement — spirit, change, the push of life. Gentle wind guides; gale-force wind uproots. The direction it pushes you is the direction something wants you to go.', reflection: 'Where is life pushing me that I keep bracing against?' },
  { keywords: ['wave', 'tsunami', 'tidal'], meaning: 'A large wave is an emotion you cannot yet contain — grief, desire, rage, awe. Tsunamis in dreams are almost never literal; they signal that something emotional is cresting whether you\'re ready or not.', reflection: 'What is cresting in me that I\'ve been trying to stand in front of?' },
  { keywords: ['desert', 'sand', 'dune'], meaning: 'Deserts are periods of spiritual dryness, stripping away, or the soul\'s testing. Crossing a desert is a real phase, not a failure. Oases in the desert are the small sustaining joys.', reflection: 'Where am I in my crossing — and what oasis am I refusing to stop at?' },
  { keywords: ['island'], meaning: 'Islands in dreams are solitude — chosen or enforced. Being alone on an island can be sacred individuation or painful exile depending on your dream-feeling about it.', reflection: 'Is this solitude nourishing me or slowly stranding me?' },
  { keywords: ['cave'], meaning: 'Caves are deep interiors — of self, of psyche, of the Mother. Entering a cave is agreeing to go inward. What you find there is often exactly what you have been avoiding in daylight.', reflection: 'What is in the cave of me that I keep almost entering?' },
  { keywords: ['labyrinth', 'maze'], meaning: 'Labyrinths represent a path that is intentionally not direct — you are meant to wander. You cannot solve a labyrinth; you can only walk it until the centre meets you.', reflection: 'What part of my life is not meant to be figured out, just walked?' },
  { keywords: ['war', 'enemy', 'opponent'], meaning: 'The enemy in a dream is usually a disowned part of yourself. The moment you understand why they fight you — what they want — is the moment integration begins.', reflection: 'What does my enemy in this dream want — and what of me have I refused to give them?' },
  { keywords: ['weapon', 'sword', 'knife', 'gun'], meaning: 'Weapons speak of how you wield power — for protection, for harm, for assertion. Holding a weapon you cannot fire often signals unspoken anger or unexpressed boundary.', reflection: 'Where is the weapon I\'m afraid to lift — and what would using it actually look like?' },
  { keywords: ['wound', 'bleeding', 'injured', 'injury'], meaning: 'Dream wounds show you where you\'re hurting in a place you haven\'t named. The location of the wound matters: head (identity/thinking), heart (love/grief), hands (doing), legs (direction).', reflection: 'Where am I wounded that I keep walking on?' },
  { keywords: ['doctor', 'hospital', 'surgery'], meaning: 'Medical settings surface when something in you needs attention, repair, or release. Surgery dreams often accompany real psychic work — something is being excised.', reflection: 'What in me is being operated on right now, in waking or dreaming?' },
  { keywords: ['teacher', 'guide', 'mentor'], meaning: 'A teacher in a dream is almost always your inner wisdom taking a face. What they say to you is something you already know at the deepest level, wrapped in a voice you can hear.', reflection: 'What did the teacher in me say — and why did I need to hear it from outside first?' },
  { keywords: ['stranger', 'unknown person'], meaning: 'Strangers often represent the Shadow — parts of you unrecognized or unintegrated. Notice whether the stranger felt threatening, helpful, or neutral; that response is about you, not them.', reflection: 'Who is this stranger actually, within me?' },
  { keywords: ['crowd', 'many people', 'audience'], meaning: 'Crowds in dreams represent the collective pressure, the many voices, or the many parts of yourself jostling for attention. Being watched by a crowd is fear of judgment or a call to be seen.', reflection: 'Whose voice in the crowd is loudest — and is it mine?' },
  { keywords: ['parent', 'mother', 'father'], meaning: 'Dream parents are rarely literal. They are the archetypes of structure (Father) and holding (Mother) as they live in you. The dream is often showing you your relationship with these forces, not with your actual parents.', reflection: 'What does the Father in me, or the Mother in me, want to say to me?' },
  { keywords: ['sibling', 'brother', 'sister'], meaning: 'Siblings in dreams often stand in for peer parts of you — the self who grew up alongside the you that got all the attention. They ask to be known too.', reflection: 'What part of me has been the overlooked sibling?' },
  { keywords: ['wedding', 'marriage', 'altar'], meaning: 'Weddings are unions — of parts of yourself coming together, or commitment to a path, or the hieros gamos (sacred marriage) of inner masculine and feminine.', reflection: 'What two parts of me are being married — and what is being vowed?' },
  { keywords: ['pregnant', 'giving birth', 'labour'], meaning: 'Pregnancy dreams signal gestation — something is growing in you that isn\'t ready to be seen yet. Giving birth is the moment of bringing it into the world. The pain is real and it is survivable.', reflection: 'What am I gestating — and am I protecting it from premature exposure?' },
  { keywords: ['breast', 'milk', 'feeding'], meaning: 'Nursing, milk, and breasts speak to nourishment — what sustains you, what you\'re asked to nourish, and who you look to for care. Empty breast or dry milk can signal depletion.', reflection: 'Who or what am I currently feeding — and is someone feeding me back?' },
  { keywords: ['insect', 'bug', 'ants', 'flies', 'cockroach'], meaning: 'Insects often represent small nagging concerns that feel beneath your attention but won\'t leave you alone. Swarms are overwhelm from the cumulative weight of small things.', reflection: 'What small thing have I been dismissing that the dream is saying matters?' },
  { keywords: ['bee', 'beehive', 'honey'], meaning: 'Bees speak of community, productive work, and the collective making of sweetness. A beehive dream is often about your relationship to belonging + labour. Honey is the reward of patient craft.', reflection: 'Where in my life am I part of a hive — and where am I flying solo when the hive would hold me?' },
  { keywords: ['wolf', 'pack'], meaning: 'Wolves are wild kin — your instinctual pack-self. They represent loyalty, the untamed feminine (La Loba), and the part of you that hunts for what it needs without apology.', reflection: 'What does my wolf-self want to reclaim?' },
  { keywords: ['lion', 'tiger', 'jaguar'], meaning: 'Large cats are majestic, dangerous, sovereign power. They represent pride, sexuality, and the part of you that will not be caged. Encountering one is an invitation to reclaim a sovereignty you\'ve softened.', reflection: 'What sovereign part of me has been waiting for me to let it roar?' },
  { keywords: ['horse', 'mustang', 'stallion'], meaning: 'Horses symbolize the body, life-force, and instinctual drive. A wild horse is untamed vitality; a tame or ridden horse is energy you\'ve learned to direct. A dying horse is a serious message about depletion.', reflection: 'How is my horse — the living-animal of me — right now?' },
  { keywords: ['fish'], meaning: 'Fish are unconscious contents rising close enough to the surface to be caught. A fish leaping from water is an insight arriving; many fish are abundance of feeling; a dead fish is a truth rotting because it wasn\'t claimed.', reflection: 'What insight is swimming up from me right now?' },
  { keywords: ['owl'], meaning: 'Owls are wisdom that sees in the dark, but also death-messengers in many traditions. They signal transitions that require you to see what others cannot.', reflection: 'What is the owl of me seeing that daylight me isn\'t ready to acknowledge?' },
  { keywords: ['raven', 'crow'], meaning: 'Ravens and crows carry between worlds. They are shadow-messengers, tricksters, and sometimes omens of necessary endings. Their arrival often precedes a real transformation.', reflection: 'What ending is being announced that I keep flinching from?' },
  { keywords: ['butterfly', 'cocoon', 'chrysalis'], meaning: 'Butterflies are transformation completed; cocoons are the phase of dissolution that precedes it. If you dream of being in a cocoon, the dream is naming that you\'re in a dissolution phase — which is not failure.', reflection: 'Am I in a dissolution phase — and can I trust the wings without seeing them yet?' },
  { keywords: ['egg'], meaning: 'Eggs are potential, unborn self, creative projects still secret. A cracked egg is disclosure or loss; many eggs are multiple possibilities competing for life.', reflection: 'Which egg of me is ready, and which is still forming?' },
  { keywords: ['seed', 'sprout', 'planting'], meaning: 'Seeds are intentional new life — what you plant is what you\'re willing to tend. Dream seeds often reflect something you\'ve recently started or committed to.', reflection: 'What seed did I just plant — and am I watering it?' },
  { keywords: ['tree'], meaning: 'Trees are the whole self — rooted below, branching above, enduring across seasons. The species matters: oak is solidity, willow is flexibility, dead tree is a part of you that has completed.', reflection: 'What tree is me — and what season is it in?' },
  { keywords: ['flower', 'blossom', 'rose'], meaning: 'Flowers are moments of beauty, opening, or soul-expression. They mark what is blooming now — often something you\'ve been tending in secret. A wilting flower is grief or the end of a phase.', reflection: 'What in me is blooming right now that I haven\'t let myself celebrate?' },
  { keywords: ['garden'], meaning: 'A garden is cultivated soul-life — what you\'ve deliberately grown. A wild garden is abundance; a neglected one is a self you\'ve stopped tending. The state of the garden reflects your current relationship to your inner life.', reflection: 'How is my garden — and what row have I been ignoring?' },
  { keywords: ['well', 'spring'], meaning: 'Wells are access to the deep self — emotional depth, ancestral wisdom, the source. A full well is availability of feeling; a dry well is depletion or blockage to your own depth.', reflection: 'Is my well deep right now, and am I letting myself drink from it?' },
  { keywords: ['ruin', 'crumbling', 'abandoned building'], meaning: 'Ruins show you what has ended in you without fanfare — old identities, old relationships, old roles. Walking through ruins is mourning done at your own pace.', reflection: 'What old structure of me has quietly ended that I haven\'t grieved?' },
  { keywords: ['tunnel'], meaning: 'Tunnels are passages through dark phases — the only way out is through. The light at the end is a real promise of the dream, not a trick. Being stuck in a tunnel is the sensation of a transition that feels longer than it is.', reflection: 'How far into the tunnel am I — and what light do I actually believe in?' },
  { keywords: ['map', 'atlas'], meaning: 'Maps in dreams are your mental model of your life. An outdated map is one of the most common dreams during transition — you\'re trying to navigate a new territory with an old chart.', reflection: 'What map of my life needs to be redrawn from where I actually am now?' },
  { keywords: ['key'], meaning: 'Keys are unlock — access, permission, or a piece of understanding you\'ve been missing. Losing a key often reflects a feeling of being locked out of your own life.', reflection: 'What key have I been looking for — and what does it open?' },
  { keywords: ['book', 'library'], meaning: 'Books are wisdom, records, stories carried across time. The library is collective memory. An unread book is knowledge that is available to you but you haven\'t opened yet.', reflection: 'What book in me have I been walking past?' },
  { keywords: ['letter', 'message', 'email'], meaning: 'Written messages in dreams are usually from the unconscious to the conscious self. You are sending yourself a message. What it says, how it arrives, and whether you open it all matter.', reflection: 'What is the message my own depth is sending me right now?' },
  { keywords: ['phone', 'call', 'ringing'], meaning: 'Phone calls are communication from psyche or from someone real who is emotionally present in your field. A phone you can\'t answer or a call you can\'t hear is often a message you aren\'t ready to receive.', reflection: 'Whose call am I afraid to pick up?' },
  { keywords: ['train station', 'waiting room'], meaning: 'Waiting in dreams often means you are in a liminal phase — between two states of life, not yet arrived, not quite departed. The waiting is itself the work.', reflection: 'What am I waiting for — and what would it mean to let the waiting be enough?' },

  // ─── Third batch (2026-04-25): expanded from 80 → 200+ symbols.
  // Modern + somatic + relational symbols that the original dictionary
  // missed but which surface constantly in real dream reports. ────
  // Modern technology
  { keywords: ['phone', 'mobile', 'cell phone', 'smartphone'], meaning: 'Phones in dreams represent the way you communicate, your sense of being reachable or unreachable, and your relationship to the world\'s noise. Lost or broken phones often signal a need to disconnect; phones that won\'t work mirror real-life feelings of being unable to be heard.', reflection: 'Who am I trying to reach — or who is trying to reach me — that I keep missing?' },
  { keywords: ['text', 'texting', 'message received'], meaning: 'A text in a dream is a compact, encoded message from the unconscious. Often it carries a single word or feeling that lingers after waking. Pay attention to who sent it and what it said — the message is for you, even if it appeared to be from someone else.', reflection: 'What short, exact message is my unconscious trying to deliver?' },
  { keywords: ['email', 'inbox', 'unread'], meaning: 'Email in dreams is the metaphor for unread, unattended responsibilities or communications you sense are waiting. An overflowing inbox surfaces overwhelm; a single unopened email can represent a single difficult conversation you\'ve been avoiding.', reflection: 'What unattended message in my life is asking to be opened?' },
  { keywords: ['social media', 'instagram', 'facebook', 'feed', 'scrolling'], meaning: 'Social media dreams reveal your relationship to performance, comparison, and the gaze of others. Dreaming of an embarrassing post often surfaces fears of being seen too truly. Endlessly scrolling without finding what you wanted mirrors a real-life search for meaning in places that can\'t provide it.', reflection: 'What am I performing online that I\'m afraid to do in private — or vice versa?' },
  { keywords: ['lost wallet', 'lost purse', 'lost id'], meaning: 'Losing a wallet, purse, or ID in dreams almost always signals an identity question: who am I, what proves I am me, and what happens when those proofs are stripped away? Often appears during career transitions and deep self-questioning.', reflection: 'What part of my identity feels unstable right now?' },
  { keywords: ['battery', 'low battery', 'dying battery', 'no charge'], meaning: 'Energy state. The unconscious uses the battery image to comment on your literal life force. A dying battery means you are running on fumes; a fully charged battery in dream means rest has worked.', reflection: 'What is depleting me faster than I am refilling it?' },
  { keywords: ['internet', 'wifi', 'no signal', 'offline'], meaning: 'Connection — to others, to information, to source. Loss of signal in dreams often arrives during periods of feeling disconnected from the people or purposes that usually orient you.', reflection: 'Where in my life have I lost signal — and how do I get back online?' },

  // Work / career
  { keywords: ['meeting', 'conference', 'boardroom'], meaning: 'Meetings in dreams reflect your sense of being seen by collective authority — bosses, peers, family elders standing in for the inner judges. Dreaming you missed an important meeting often surfaces fear of letting down a structure you\'re trying to belong to.', reflection: 'Whose approval is the meeting I\'m worried about really seeking?' },
  { keywords: ['boss', 'supervisor', 'manager'], meaning: 'A boss-figure in a dream is rarely the literal boss; it\'s your inner authority structure. The way you behave toward them in the dream shows how you treat your own self-discipline, ambition, or guilt.', reflection: 'How am I treating my inner authority — like a tyrant, an ally, or a stranger?' },
  { keywords: ['fired', 'getting fired', 'losing my job', 'pink slip'], meaning: 'Being fired in dreams almost never predicts actual termination. It usually surfaces a sense that you are not playing the role expected of you, or a part of yourself is ready to be released from a duty you\'ve outgrown.', reflection: 'What role am I being asked to release that I keep clinging to?' },
  { keywords: ['promotion', 'raise', 'recognition'], meaning: 'Recognition dreams reflect a need to be seen for what you have actually been doing, not necessarily a literal forecast. Often surfaces during periods of unsung effort — the unconscious validating what the world has not yet noticed.', reflection: 'What work of mine deserves recognition that I have been minimising?' },
  { keywords: ['interview', 'job interview', 'audition'], meaning: 'You are being evaluated. The interviewer is a part of yourself appraising your readiness. The questions you struggle to answer are exactly the questions you need to answer in waking life.', reflection: 'What about myself am I currently being asked to articulate that I haven\'t yet?' },

  // Body + somatic
  { keywords: ['heart', 'heartbeat', 'pounding heart'], meaning: 'The heart in dreams is the seat of feeling — particularly love, grief, courage, vulnerability. A racing heart can be the body processing real anxiety or excitement; a still heart is calm or sometimes emotional shutdown.', reflection: 'What is my heart trying to tell me that my mind keeps interrupting?' },
  { keywords: ['blood', 'bleeding', 'wound bleeding'], meaning: 'Blood is life force — vitality leaving you, or being demanded of you. Watch where you\'re bleeding from: head (overthinking taking a toll), heart (emotional cost), hands (work depletion), feet (path causing harm).', reflection: 'Where am I bleeding life force without realising it?' },
  { keywords: ['voice', 'cant speak', 'lost my voice', 'mute'], meaning: 'Inability to speak in dreams is one of the most common — and one of the most direct signals from the unconscious. Something needs to be said and you are not saying it. The dream version of the silenced throat is asking for the waking version of speech.', reflection: 'What words am I swallowing that need to come out?' },
  { keywords: ['breath', 'cant breathe', 'suffocating', 'drowning air'], meaning: 'Breathlessness in dreams often surfaces real-life feeling of not being able to take in enough room — emotionally, financially, time-wise. The body translates "I have no space" into the literal sensation of not being able to inhale.', reflection: 'Where in my life have I run out of room?' },
  { keywords: ['eyes', 'cant see', 'blurred vision', 'blind'], meaning: 'Vision is consciousness, perception, the ability to discern. Blurred or lost sight in dreams reflects waking confusion or a refusal to see something clearly. Sometimes also surfaces during major perspective shifts when the old way of seeing is breaking down.', reflection: 'What am I refusing to look at clearly?' },
  { keywords: ['running', 'cant run', 'legs heavy', 'molasses'], meaning: 'The classic anxiety-dream sensation of trying to run but moving in slow motion is one of the most universal dream experiences. It surfaces when you feel pursued by a problem you can\'t outpace — and the dream is correct: you can\'t outrun it.', reflection: 'What am I trying to escape that I haven\'t agreed to face?' },
  { keywords: ['vomit', 'throwing up', 'sick'], meaning: 'Vomiting in dreams is often purgative rather than alarming — your unconscious expelling something it cannot digest. Note what you vomited: food (something taken in too fast), words (something you couldn\'t hold inside), an object (something foreign trying to leave you).', reflection: 'What am I trying to expel from my system?' },

  // Family + relational
  { keywords: ['ex', 'ex-partner', 'former lover'], meaning: 'A dream about an ex is rarely about that specific person — it\'s about the qualities they represented in you, the part of yourself you were when you were with them, or the unfinished psychic business of that chapter. They often appear when their archetypal energy is needed again.', reflection: 'What quality from that chapter of my life is asking to come back?' },
  { keywords: ['stranger appearing', 'unknown person'], meaning: 'A stranger in your dream is almost always a part of you that has not yet been integrated — your shadow, your unrealized potential, or a projection of what you fear or admire. Notice what you felt about them.', reflection: 'What do I see in this stranger that is mine?' },
  { keywords: ['friend', 'old friend', 'childhood friend'], meaning: 'Old friends in dreams carry the qualities they had when you knew them — innocence, freedom, hopefulness, certain forms of joy you have lost touch with. Dreaming of them is often a call to reclaim those qualities, not necessarily to reconnect literally.', reflection: 'What part of who I was with them is asking for room again?' },
  { keywords: ['twin', 'doppelganger', 'looks like me'], meaning: 'Encountering yourself in a dream — a twin, a copy, a doppelganger — is the unconscious dramatising integration. Two parts of you are meeting. Whether the encounter is friendly or hostile shows the current state of your relationship with the disowned part.', reflection: 'What part of me am I meeting — and how am I treating them?' },
  { keywords: ['child of mine', 'my child', 'my baby'], meaning: 'Even for non-parents, dream-children often represent your creative output, projects, and the parts of you that need tending. Your relationship with the dream-child shows your relationship with your own vulnerability.', reflection: 'What tender thing of mine is asking to be cared for?' },
  { keywords: ['being chased by family', 'family chasing me'], meaning: 'Pursuit by family members in dreams often surfaces unresolved family expectations, generational patterns trying to claim you, or a sense of trying to escape the role you were assigned at home.', reflection: 'What family expectation am I currently running from — and what would it cost to turn and face?' },

  // Nature + environment expanded
  { keywords: ['rainbow'], meaning: 'Rainbows symbolise integration after rain — the bridge between sorrow and joy, between separated parts. They often appear in dreams after a hard inner phase has just resolved.', reflection: 'What in me has just integrated that I haven\'t yet noticed?' },
  { keywords: ['eclipse', 'solar eclipse', 'lunar eclipse'], meaning: 'Eclipses are temporary occultations — light blocked, then returning. They appear in dreams when something temporarily obscures your usual sense of self or guidance, often before a major transformation. The darkness is brief; trust it.', reflection: 'What temporary blackout is teaching me something the daylight couldn\'t?' },
  { keywords: ['meteor', 'shooting star', 'comet'], meaning: 'A celestial event crossing your sky — sudden insight, an unexpected visitor, a wish forming. Often heralds imminent change that has been building unseen.', reflection: 'What is about to streak across my life that I have been wishing for?' },
  { keywords: ['moon phases', 'full moon', 'new moon'], meaning: 'Lunar phases mirror your emotional cycle. Full moons in dreams arrive at peaks — full feeling, full visibility. New moons signal beginnings still hidden. Track which phase your dream-moon is in; the unconscious is timing you.', reflection: 'What phase am I in right now that the moon is showing me?' },
  { keywords: ['ocean', 'tide', 'low tide', 'high tide'], meaning: 'Beyond water generally, the ocean is the deep collective unconscious — the vastness greater than any individual psyche. Tides reflect emotional cycles. A receding tide reveals what was hidden; a rising tide brings fullness or overwhelm.', reflection: 'What does the ocean of me look like right now — calm, stormy, ebbing, flooding?' },
  { keywords: ['volcano', 'lava', 'eruption'], meaning: 'Volcanoes are accumulated pressure breaking through — anger, suppressed creative energy, deep transformation that can no longer be held. The eruption is not the disaster; the suppression that built up to it was.', reflection: 'What has been pressurising in me that needs a deliberate channel before it erupts on its own?' },
  { keywords: ['earthquake', 'tremor', 'shaking ground'], meaning: 'The ground itself is moving — a foundational belief, identity, or relationship structure is shaking. Often dreams arrive during or just before major life-restructure events, the unconscious previewing what the conscious mind hasn\'t agreed to yet.', reflection: 'What foundation in my life is shifting that I keep trying to stabilise?' },
  { keywords: ['stars', 'starry sky', 'constellation'], meaning: 'Stars are the eternal — what continues when individual lives end. Dreams featuring vast starry skies often arrive in moments of perspective: when you most need to remember that your specific struggle is small against the immensity that holds it.', reflection: 'What does the perspective of stars give me about my current worry?' },

  // Food + consumption
  { keywords: ['eating', 'food', 'meal'], meaning: 'Eating in dreams is taking in — nourishment, ideas, experiences, others\' energy. What you\'re eating matters: rich food (abundance, sensuality), forbidden food (taboo desires), spoiled food (something tainted you\'re absorbing anyway).', reflection: 'What am I taking in right now — and is it nourishing me or making me sick?' },
  { keywords: ['hungry', 'starving', 'cant find food'], meaning: 'Hunger in dreams represents what you are not getting that you need — emotional, creative, sensual, spiritual nourishment. The kind of hunger reveals the kind of starvation: stomach (literal nourishment / belonging), heart (love), throat (voice and expression).', reflection: 'What hunger have I been trying to ignore?' },
  { keywords: ['cooking', 'baking', 'preparing meal'], meaning: 'Cooking is creative transformation — taking raw ingredients and turning them into something new. Dreams of cooking surface during creative project phases. How well the cooking goes mirrors how the project is going.', reflection: 'What raw material in my life am I turning into something nourishing?' },
  { keywords: ['poison', 'poisoned food', 'toxic'], meaning: 'Poison in food represents something you\'re consuming — relationship dynamic, work environment, media diet, internal narrative — that is harming you slowly. The dream warns specifically: this looks like nourishment, but isn\'t.', reflection: 'What in my life looks healthy but is actually toxic?' },
  { keywords: ['drinking water', 'thirsty', 'cant find water'], meaning: 'Thirst is for the deep emotional life — for feeling, for intimacy, for the source. Dreams of being unable to find water surface during periods of emotional starvation or spiritual dryness.', reflection: 'What does my thirst tell me about what I\'ve been denying myself?' },

  // Domestic + everyday
  { keywords: ['locked out', 'cant get in', 'wrong key'], meaning: 'Being locked out of your own home, car, or workplace dreams during periods of feeling exiled from a place you used to belong, or when an old identity no longer grants access.', reflection: 'What place in my life have I been locked out of — and is the door truly closed, or am I trying the wrong key?' },
  { keywords: ['moving house', 'new house', 'unfamiliar house'], meaning: 'Moving represents identity transition. New houses in dreams often appear during major life shifts — a relationship ending, career change, geographic move, or inner transformation reorganising your sense of home.', reflection: 'What inner home is being reorganised in me right now?' },
  { keywords: ['cleaning', 'sweeping', 'organising'], meaning: 'Cleaning dreams reflect literal or symbolic clearing — purging old patterns, organising mental clutter, completing what was left undone. Often arrive during transitional phases when the psyche is preparing room.', reflection: 'What am I clearing out that\'s been due for a sweep?' },
  { keywords: ['breaking', 'broken object', 'shattered'], meaning: 'Something has cracked. The dream often anticipates an actual breaking point — in a relationship, a routine, a held belief. The breaking is not always loss; sometimes it\'s the necessary release of something you had been holding too tightly.', reflection: 'What has finally cracked open that I had been gripping?' },
  { keywords: ['lost luggage', 'missing bag', 'forgot suitcase'], meaning: 'Lost luggage represents lost or forgotten parts of self that you\'re carrying through transition. Often arrives during travel-of-life moments when you sense you\'ve left something behind that you may need.', reflection: 'What did I leave behind in the move that I now realise I need?' },

  // Power + action
  { keywords: ['hiding', 'cant be found', 'closet'], meaning: 'Hiding in dreams reflects a part of you that doesn\'t want to be found — by responsibility, by another person, by a truth. The hiding place itself is significant: under the bed (childhood retreat), in a closet (hidden identity), behind a door (a specific avoidance).', reflection: 'What part of me is hiding — and from whom?' },
  { keywords: ['searching', 'looking for something lost'], meaning: 'A search dream is the unconscious looking for what you lost touch with. The thing being searched for is rarely the literal thing — it\'s the quality that thing represents (security, lost love, a past version of self).', reflection: 'What am I really searching for behind what I think I\'m searching for?' },
  { keywords: ['flying without wings', 'levitating'], meaning: 'Levitation distinguishes from full flight — the body rises but uncertainly, often only briefly. Surfaces in moments of rising spiritual or creative awareness that hasn\'t yet stabilised. You\'re lifting, but not yet flying.', reflection: 'What is rising in me that I don\'t yet trust to fully leave the ground?' },
  { keywords: ['rescuing someone', 'saving', 'pulling out of'], meaning: 'Rescue dreams cast you as the helper. The person or creature being rescued is often a vulnerable part of yourself. The act of saving them in the dream is your psyche acknowledging that it can save itself.', reflection: 'What part of me am I being asked to rescue?' },

  // Spiritual + symbolic
  { keywords: ['angel', 'angelic figure', 'guardian'], meaning: 'Angelic figures in dreams represent benevolent guidance — your higher self, an inner protector, ancestral support, or what some traditions call a soul friend. They appear in moments when you most need to remember you are not alone.', reflection: 'What guidance is reaching me that I have been resisting?' },
  { keywords: ['demon', 'devil', 'evil entity'], meaning: 'Demonic figures in dreams represent disowned shadow material — the parts of yourself you have rejected so completely they have become almost "other". The way to disempower them in the dream and waking life is the same: turn and face them.', reflection: 'What in me have I rejected so completely it now feels foreign?' },
  { keywords: ['god', 'goddess', 'divine presence'], meaning: 'Direct encounters with divine presence in dreams are rare and often life-altering. They surface in moments of profound transition. Pay attention not to what was said but to what was felt.', reflection: 'What was the felt-sense of being seen this fully — and how would my life change if I lived as if I were always being seen this way?' },
  { keywords: ['ghost', 'spirit', 'presence'], meaning: 'Ghosts represent the unfinished — relationships not properly closed, emotions not fully felt, deaths not fully grieved. They visit when they need acknowledgement.', reflection: 'What unfinished thing is asking to be completed?' },
  { keywords: ['reincarnation', 'past life', 'former life'], meaning: 'Past-life dreams need not be taken literally to be valuable. They often dramatise psychological "former lives" — old identities, past relationships, who you used to be — that are still influencing the present.', reflection: 'What former version of me is still living in my current life?' },

  // Sound + music
  { keywords: ['music', 'song', 'singing'], meaning: 'Music in dreams expresses what cannot be said in words — emotional truth, longing, joy, mourning. Listen to what the music makes you feel; that feeling is the message.', reflection: 'What feeling is the music in me carrying that I haven\'t given language to?' },
  { keywords: ['silence', 'cant hear', 'deafness'], meaning: 'Inability to hear in dreams reflects a refusal to listen — to others, to your own inner voice, to the message life is sending. Sometimes also surfaces during periods of necessary withdrawal from too much input.', reflection: 'What am I refusing to hear?' },
  { keywords: ['knocking', 'door bell', 'knock'], meaning: 'A knock at the door in dreams is the unconscious announcing arrival — a new phase, a returning energy, a part of you ready to be acknowledged. Whether you open the door matters.', reflection: 'What is knocking — and am I ready to open?' },

  // Identity + transformation
  { keywords: ['mask', 'masked', 'face covered'], meaning: 'Masks represent persona — the face shown to the world. Dreams of masks (yours or others\') surface when the gap between presented self and inner self has grown. Removing the mask is the work.', reflection: 'What mask am I wearing that I no longer need?' },
  { keywords: ['costume', 'dressed as', 'wearing different clothes'], meaning: 'Costume dreams play with identity — what would it be like to be a different version of self? Often surface during transition phases when you\'re trying on new ways of being.', reflection: 'What new version of me am I auditioning for?' },
  { keywords: ['naked in public', 'undressed in front of others'], meaning: 'The classic exposure dream. Surfaces during periods of feeling judged, evaluated, or seen too truly. The vulnerability is the point — what would it mean to be seen fully without dressing up?', reflection: 'Where have I been afraid of being seen as I really am?' },
  { keywords: ['transforming', 'changing into', 'becoming animal'], meaning: 'Transformation dreams — turning into an animal, growing wings, changing shape — express identity work happening at deep unconscious levels. The animal you become carries information: which qualities are emerging.', reflection: 'What new part of me is emerging that the dream is dramatising?' },

  // Movement + travel expanded
  { keywords: ['highway', 'driving fast', 'speeding'], meaning: 'High-speed travel reflects life moving faster than your nervous system can metabolise. Often arrives during periods of overwhelm — too many decisions, too quickly. The dream warns: slow down before something forces it.', reflection: 'Where am I going faster than I can integrate?' },
  { keywords: ['lost driver', 'wrong turn', 'gps not working'], meaning: 'Navigation failure in dreams reflects waking confusion about life direction. The map is outdated. The dream is not telling you which way to go — it\'s telling you the old route doesn\'t apply.', reflection: 'What old map of my life am I still trying to follow?' },
  { keywords: ['returning home', 'going home', 'back home'], meaning: 'Returning to a childhood home or hometown in dreams surfaces work with origins — what to integrate from where you came, what to release. The state of the dream-home reflects the state of your psyche\'s relationship with its roots.', reflection: 'What about home is asking for return — and what is asking to be released?' },
  { keywords: ['boat sinking', 'sinking ship'], meaning: 'A sinking vessel is a structure failing — a relationship, a job, a life-arrangement that can no longer hold you. Dreams of sinking warn that the structure is past saving; the work is to get to the lifeboat with what matters.', reflection: 'What in my life is sinking that I have been trying to save?' },
  { keywords: ['stairs broken', 'fall down stairs'], meaning: 'Stairs are progress — ascending stairs is rising, descending is going within. Falling on stairs reflects sudden setbacks during transitions, or the discovery that the route you were taking didn\'t hold.', reflection: 'Where have I just had a setback that the dream is processing?' },

  // Emotion-specific
  { keywords: ['crying', 'tears', 'sobbing'], meaning: 'Crying in dreams releases what waking life has been holding back. The tears are real even though the dream is not — your psyche is doing the grief work the conscious mind hasn\'t made room for.', reflection: 'What grief am I holding that needs space to be cried?' },
  { keywords: ['laughing', 'cant stop laughing'], meaning: 'Genuine laughter in dreams often arrives during integration — a difficult thing has resolved and the body is celebrating. Hysterical laughter can also be a release of tension that had no other outlet.', reflection: 'What just resolved in me that I haven\'t yet celebrated?' },
  { keywords: ['screaming', 'cant scream'], meaning: 'A scream is the demand to be heard at maximum volume. Inability to scream in a dream reflects waking voicelessness in a situation where your life depends on speaking up.', reflection: 'What is so urgent it\'s asking to be screamed — and where am I muting it?' },
  { keywords: ['embarrassed', 'humiliated', 'shame'], meaning: 'Shame dreams surface when self-judgement is running ahead of self-acceptance. The dream brings the shame to the surface so it can be looked at instead of buried.', reflection: 'What am I ashamed of that needs the kindness I would offer a friend in the same situation?' },

  // Numbers, repetition, time
  { keywords: ['number repeating', 'three of', 'seeing 333'], meaning: 'Repeating numbers in dreams ask for attention to the symbolism of that number. 1 = beginning. 2 = duality, partnership. 3 = creative completion. 7 = mystery + spiritual development. 13 = transition. The dream is timing-stamping a message.', reflection: 'What does the specific number recurring in my dream want me to notice?' },
  { keywords: ['time stopped', 'cant tell time', 'clock broken'], meaning: 'Disrupted time in dreams reflects a feeling that life chronology has lost its grip — too much, too fast, or trapped in repetition. The clock is metaphorical; what\'s breaking is your usual relationship to past/present/future.', reflection: 'What about my usual sense of time isn\'t working anymore?' },
  { keywords: ['repeating dream', 'same dream', 'recurring'], meaning: 'A recurring dream is the unconscious knocking with the same letter until it gets read. The repetition itself is the message: this matters, you haven\'t addressed it, here it is again.', reflection: 'What hasn\'t been addressed that keeps coming back?' },

  // Thresholds + initiation
  { keywords: ['ceremony', 'ritual', 'initiation'], meaning: 'Ritual / ceremony dreams mark psychological initiation — moving from one phase of life to another. They often arrive at thresholds the waking mind hasn\'t yet acknowledged: ending of youth, becoming a parent, professional arrival.', reflection: 'What threshold am I crossing that deserves to be marked rather than slid past?' },
  { keywords: ['exam', 'final exam', 'havent studied'], meaning: 'The classic exam dream surfaces during evaluation periods — interviews, performance reviews, big projects. The unpreparedness reflects fear, but often the dream\'s fear exceeds reality.', reflection: 'What evaluation am I anticipating — and is my fear of it bigger than the actual stakes?' },
  { keywords: ['graduation', 'finishing school'], meaning: 'Graduation dreams mark the completion of a long phase. Often arrive at the end of personal growth chapters that didn\'t have a formal end-marker. The unconscious provides the ritual close that life skipped.', reflection: 'What chapter of mine is actually complete that I haven\'t fully acknowledged?' },
];

export interface DreamReading {
  matchedSymbols: {
    symbol: DreamSymbol;
    keyword: string;
  }[];
  coreTheme: string;
  reflections: string[];
  hasMatch: boolean;
}

// Strip apostrophes (straight, curly, or backtick variants) so that
// keywords stored without apostrophes — e.g. "cant scream", "havent
// studied" — still match the way real users type them ("can't scream",
// "haven't studied"). Without this, ~11 of the 80 keywords are dead
// letters because users almost never type contractions without the
// apostrophe.
function normalizeForKeywordMatch(s: string): string {
  return s.toLowerCase().replace(/[’‘'`´]/g, '');
}

// Match user-input dream text against symbol dictionary.
// Case-insensitive, whole-word-boundary matching where possible.
export function interpretDream(dreamText: string): DreamReading {
  const text = normalizeForKeywordMatch(dreamText);
  const matched: { symbol: DreamSymbol; keyword: string }[] = [];
  const seenSymbols = new Set<DreamSymbol>();

  for (const symbol of DREAM_SYMBOLS) {
    if (seenSymbols.has(symbol)) continue;
    for (const keyword of symbol.keywords) {
      const normalized = normalizeForKeywordMatch(keyword);
      const re = new RegExp(`\\b${normalized.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}\\b`, 'i');
      if (re.test(text)) {
        matched.push({ symbol, keyword });
        seenSymbols.add(symbol);
        break;
      }
    }
  }

  const hasMatch = matched.length > 0;

  let coreTheme = '';
  if (hasMatch) {
    if (matched.length === 1) {
      coreTheme = `Your dream carries the archetype of **${matched[0].keyword}** at its centre.`;
    } else if (matched.length <= 3) {
      const words = matched.map((m) => `**${m.keyword}**`).join(', ');
      coreTheme = `Three symbols move through this dream: ${words}. Their dance is the message.`;
    } else {
      coreTheme = `Your dream is rich — ${matched.length} archetypal symbols appear, each offering its own thread. The dream wants to be sat with, not solved.`;
    }
  }

  return {
    matchedSymbols: matched,
    coreTheme,
    reflections: matched.map((m) => m.symbol.reflection),
    hasMatch,
  };
}
